  1	import * as React from 'react';
  2	import { useCustomTranslation } from '@odf/shared/useCustomTranslationHook';
  3	import { consoleFetch } from '@openshift-console/dynamic-plugin-sdk';
  4	import {
  5	  Modal,
  6	  ModalVariant,
  7	  Button,
  8	  ButtonVariant,
  9	  FormGroup,
 10	  InputGroup,
 11	  InputGroupItem,
 12	  NumberInput,
 13	  Select,
 14	  SelectList,
 15	  SelectOption,
 16	  MenuToggle,
 17	  MenuToggleElement,
 18	  Alert,
 19	  AlertVariant,
 20	} from '@patternfly/react-core';
 21	import { BellIcon } from '@patternfly/react-icons';
 22	import { AlertRowData } from './hooks';
 23	
 24	type DurationUnit = 'hours' | 'days' | 'weeks';
 25	
 26	type SilenceAlertModalProps = {
 27	  isOpen: boolean;
 28	  onClose: () => void;
 29	  selectedAlerts: AlertRowData[];
 30	  alertManagerBasePath: string;
 31	  onSuccess?: () => void;
 32	};
 33	
 34	const DURATION_UNIT_MULTIPLIERS: Record<DurationUnit, number> = {
 35	  hours: 60 * 60 * 1000,
 36	  days: 24 * 60 * 60 * 1000,
 37	  weeks: 7 * 24 * 60 * 60 * 1000,
 38	};
 39	
 40	export const SilenceAlertModal: React.FC<SilenceAlertModalProps> = ({
 41	  isOpen,
 42	  onClose,
 43	  selectedAlerts,
 44	  alertManagerBasePath,
 45	  onSuccess,
 46	}) => {
 47	  // Custom hooks
 48	  const { t } = useCustomTranslation();
 49	
 50	  // State hooks
 51	  const [durationValue, setDurationValue] = React.useState(1);
 52	  const [durationUnit, setDurationUnit] = React.useState<DurationUnit>('hours');
 53	  const [isUnitSelectOpen, setIsUnitSelectOpen] = React.useState(false);
 54	  const [isSubmitting, setIsSubmitting] = React.useState(false);
 55	  const [error, setError] = React.useState<string | null>(null);
 56	
 57	  // Refs - Modal content container for scoped input access
 58	  const modalContentRef = React.useRef<HTMLDivElement>(null);
 59	
 60	  // Memoized values
 61	  const durationUnitOptions = React.useMemo(
 62	    () => [
 63	      { value: 'hours', label: t('hours') },
 64	      { value: 'days', label: t('days') },
 65	      { value: 'weeks', label: t('weeks') },
 66	    ],
 67	    [t]
 68	  );
 69	
 70	  // Event handlers
 71	  const handleDurationChange = (event: React.FormEvent<HTMLInputElement>) => {
 72	    const value = (event.target as HTMLInputElement).value;
 73	    const numValue = parseInt(value, 10);
 74	    setDurationValue(isNaN(numValue) ? 0 : Math.max(0, numValue));
 75	  };
 76	
 77	  const handleMinus = () => {
 78	    setDurationValue((prev) => Math.max(0, prev - 1));
 79	  };
 80	
 81	  const handlePlus = () => {
 82	    setDurationValue((prev) => prev + 1);
 83	  };
 84	
 85	  // Callbacks
 86	  const handleUnitSelect = React.useCallback(
 87	    (_event: React.MouseEvent | undefined, selection: string) => {
 88	      setDurationUnit(selection as DurationUnit);
 89	      setIsUnitSelectOpen(false);
 90	    },
 91	    []
 92	  );
 93	
 94	  const createSilence = async () => {
 95	    if (!alertManagerBasePath || durationValue <= 0) {
 96	      return;
 97	    }
 98	
 99	    setIsSubmitting(true);
100	    setError(null);
101	
102	    try {
103	      const now = new Date();
104	      const durationMs =
105	        durationValue * DURATION_UNIT_MULTIPLIERS[durationUnit];
106	      const endsAt = new Date(now.getTime() + durationMs);
107	
108	      // Create matchers from all selected alerts' labels
109	      // We need to create a separate silence for each alert since they may have different labels
110	      const silencePromises = selectedAlerts.map((alert) => {
111	        const matchers = Object.entries(alert.labels).map(([name, value]) => ({
112	          name,
113	          value,
114	          isRegex: false,
115	          isEqual: true,
116	        }));
117	
118	        const silenceData = {
119	          matchers,
120	          startsAt: now.toISOString(),
121	          endsAt: endsAt.toISOString(),
122	          comment: t(
123	            'Silenced via ODF Health Overview for {{duration}} {{unit}}',
124	            { duration: durationValue, unit: durationUnit }
125	          ),
126	          createdBy: 'odf-console',
127	        };
128	
129	        return consoleFetch(`${alertManagerBasePath}/api/v2/silences`, {
130	          method: 'POST',
131	          headers: {
132	            'Content-Type': 'application/json',
133	          },
134	          body: JSON.stringify(silenceData),
135	        }).then((response) => {
136	          if (!response?.ok) {
137	            throw new Error(
138	              `${response.status} ${response.statusText || t('Unknown error')}`
139	            );
140	          }
141	          return response.json();
142	        });
143	      });
144	
145	      await Promise.all(silencePromises);
146	
147	      // Success - close modal and notify parent
148	      onSuccess?.();
149	      onClose();
150	
151	      // Reset form
152	      setDurationValue(1);
153	      setDurationUnit('hours');
154	    } catch (err) {
155	      setError(
156	        err instanceof Error
157	          ? err.message
158	          : t('Failed to create silence. Please try again.')
159	      );
160	    } finally {
161	      setIsSubmitting(false);
162	    }
163	  };
164	
165	  const handleClose = () => {
166	    if (!isSubmitting) {
167	      setError(null);
168	      // reset duration and unit values on close / cancel
169	      setDurationValue(1);
170	      setDurationUnit('hours');
171	      onClose();
172	    }
173	  };
174	
175	  const isSilenceDisabled = durationValue <= 0 || isSubmitting;
176	
177	  const unitToggle = (toggleRef: React.Ref<MenuToggleElement>) => (
178	    <MenuToggle
179	      ref={toggleRef}
180	      onClick={() => setIsUnitSelectOpen((prev) => !prev)}
181	      isExpanded={isUnitSelectOpen}
182	      style={{ minWidth: '120px' }}
183	    >
184	      {durationUnitOptions.find((opt) => opt.value === durationUnit)?.label ||
185	        t('hours')}
186	    </MenuToggle>
187	  );
188	
189	  // Effects - Auto focus on duration input when modal opens
190	  React.useEffect(() => {
191	    if (isOpen && modalContentRef.current) {
192	      // Use setTimeout to ensure the modal is fully rendered before focusing
193	      setTimeout(() => {
194	        const input = modalContentRef.current?.querySelector(
195	          'input[name="duration"]'
196	        ) as HTMLInputElement;
197	        input?.focus();
198	      }, 100);
199	    }
200	  }, [isOpen]);
201	
202	  return (
203	    <Modal
204	      variant={ModalVariant.small}
205	      title={
206	        <span>
207	          <BellIcon className="pf-v6-u-mr-sm" />
208	          {t('Silence alert')}
209	        </span>
210	      }
211	      isOpen={isOpen}
212	      onClose={handleClose}
213	      actions={[
214	        <Button
215	          key="silence"
216	          variant={ButtonVariant.primary}
217	          onClick={createSilence}
218	          isDisabled={isSilenceDisabled}
219	          isLoading={isSubmitting}
220	        >
221	          {t('Silence')}
222	        </Button>,
223	        <Button
224	          key="cancel"
225	          variant={ButtonVariant.link}
226	          onClick={handleClose}
227	          isDisabled={isSubmitting}
228	        >
229	          {t('Cancel')}
230	        </Button>,
231	      ]}
232	    >
233	      <div ref={modalContentRef}>
234	        <p className="pf-v6-u-mb-md">
235	          {t(
236	            'Temporarily mute alerts matching the selected checks and conditions. Silenced alerts will not appear in the table or affect the health score.'
237	          )}
238	        </p>
239	
240	        {error && (
241	          <Alert
242	            variant={AlertVariant.danger}
243	            isInline
244	            title={t('Error creating silence')}
245	            className="pf-v6-u-mb-md"
246	          >
247	            {error}
248	          </Alert>
249	        )}
250	
251	        <FormGroup label={t('Duration')} isRequired>
252	          <InputGroup>
253	            <InputGroupItem isFill>
254	              <NumberInput
255	                value={durationValue}
256	                onChange={handleDurationChange}
257	                onMinus={handleMinus}
258	                onPlus={handlePlus}
259	                min={0}
260	                inputName="duration"
261	                inputAriaLabel={t('Duration value')}
262	                minusBtnAriaLabel={t('Decrease duration')}
263	                plusBtnAriaLabel={t('Increase duration')}
264	                widthChars={10}
265	                isDisabled={isSubmitting}
266	              />
267	            </InputGroupItem>
268	            <InputGroupItem>
269	              <Select
270	                isOpen={isUnitSelectOpen}
271	                selected={durationUnit}
272	                onSelect={handleUnitSelect}
273	                onOpenChange={setIsUnitSelectOpen}
274	                toggle={unitToggle}
275	                isDisabled={isSubmitting}
276	                shouldFocusFirstItemOnOpen
277	                shouldFocusToggleOnSelect
278	              >
279	                <SelectList>
280	                  {durationUnitOptions.map((option) => (
281	                    <SelectOption key={option.value} value={option.value}>
282	                      {option.label}
283	                    </SelectOption>
284	                  ))}
285	                </SelectList>
286	              </Select>
287	            </InputGroupItem>
288	          </InputGroup>
289	        </FormGroup>
290	
291	        {selectedAlerts.length > 0 && (
292	          <Alert
293	            variant={AlertVariant.info}
294	            isInline
295	            isPlain
296	            title={t('{{count}} alert(s) will be silenced', {
297	              count: selectedAlerts.length,
298	            })}
299	            className="pf-v6-u-mt-md"
300	          />
301	        )}
302	      </div>
303	    </Modal>
304	  );
305	};

